// Sentiment Snapshot - Merge & Calculate Risk Appetite Score
// Weights: CNN F&G 30%, Crypto F&G inverse 20%, VIX inverted 30%, DXY 20%

const now = new Date();
const madridOffset = 1; // CET (UTC+1), CEST would be 2 but n8n runs in server time
const fecha = now.toLocaleDateString('es-ES', { timeZone: 'Europe/Madrid', day: '2-digit', month: '2-digit', year: 'numeric' });
const hora = now.toLocaleTimeString('es-ES', { timeZone: 'Europe/Madrid', hour: '2-digit', minute: '2-digit' });

// Extract CNN Fear & Greed data
let cnnScore = 50;
let cnnRating = 'Neutral';
let cnnChangeYday = 0;
let cnnChangeWeek = 0;

if ($input.first().json.fearandgreed) {
  const fg = $input.first().json.fearandgreed;
  cnnScore = fg.current?.value ?? 50;
  cnnRating = fg.current?.rating ?? 'Neutral';
  cnnChangeYday = fg.current?.previousClose !== undefined && fg.historical?.values?.[1] 
    ? Math.round((fg.current.value - fg.historical.values[1].value) * 10) / 10 
    : 0;
  cnnChangeWeek = fg.current?.oneWeekAgo !== undefined 
    ? Math.round((fg.current.value - fg.current.oneWeekAgo) * 10) / 10 
    : 0;
}

// Extract Crypto Fear & Greed data
let cryptoScore = 50;
let cryptoRating = 'Neutral';
let cryptoChangeYday = 0;

if ($input.item(1).json.data && $input.item(1).json.data.length >= 2) {
  const today = $input.item(1).json.data[0];
  const yesterday = $input.item(1).json.data[1];
  cryptoScore = parseInt(today.value);
  cryptoRating = today.value_classification;
  cryptoChangeYday = cryptoScore - parseInt(yesterday.value);
}

// Extract VIX data
let vixClose = 20;
let vixChange5d = 0;
let vixLevel = 'medium';

if ($input.item(2).json.chart && $input.item(2).json.chart.result && $input.item(2).json.chart.result[0]) {
  const result = $input.item(2).json.chart.result[0];
  const closes = result.indicators.quote[0].close.filter(c => c !== null);
  if (closes.length > 0) {
    vixClose = Math.round(closes[closes.length - 1] * 100) / 100;
    if (closes.length >= 5) {
      vixChange5d = Math.round((closes[closes.length - 1] - closes[closes.length - 5]) * 100) / 100;
    }
  }
  if (vixClose < 15) vixLevel = 'low';
  else if (vixClose <= 25) vixLevel = 'medium';
  else vixLevel = 'high';
}

// Extract DXY data
let dxyPrice = 100;
let dxyChangeWeek = 0;
let dxyTrend = 'flat';

if ($input.item(3).json.chart && $input.item(3).json.chart.result && $input.item(3).json.chart.result[0]) {
  const result = $input.item(3).json.chart.result[0];
  const closes = result.indicators.quote[0].close.filter(c => c !== null);
  if (closes.length >= 2) {
    dxyPrice = Math.round(closes[closes.length - 1] * 100) / 100;
    dxyChangeWeek = Math.round(((closes[closes.length - 1] - closes[0]) / closes[0] * 100) * 100) / 100;
    if (dxyChangeWeek > 0.5) dxyTrend = 'up';
    else if (dxyChangeWeek < -0.5) dxyTrend = 'down';
  }
}

// Extract Gold data
let goldPrice = 2000;
if ($input.item(4).json.chart && $input.item(4).json.chart.result && $input.item(5).json.chart.result[0]) {
  const goldResult = $input.item(4).json.chart.result[0];
  const goldCloses = goldResult.indicators.quote[0].close.filter(c => c !== null);
  if (goldCloses.length > 0) {
    goldPrice = Math.round(goldCloses[goldCloses.length - 1] * 100) / 100;
  }
}

// Extract Oil data and calculate Gold/Oil ratio
let oilPrice = 80;
let goldOilRatio = 25;
let goldOilTrend = 'flat';

if ($input.item(5).json.chart && $input.item(5).json.chart.result && $input.item(5).json.chart.result[0]) {
  const oilResult = $input.item(5).json.chart.result[0];
  const oilCloses = oilResult.indicators.quote[0].close.filter(c => c !== null);
  if (oilCloses.length > 0) {
    oilPrice = Math.round(oilCloses[oilCloses.length - 1] * 100) / 100;
    goldOilRatio = Math.round((goldPrice / oilPrice) * 100) / 100;

    // Calculate trend from first to last week value
    if (oilCloses.length >= 5) {
      const goldOilWeekAgo = goldPrice / oilCloses[0];
      const currentRatio = goldPrice / oilCloses[oilCloses.length - 1];
      const ratioChange = currentRatio - goldOilWeekAgo;
      if (ratioChange > 0.5) goldOilTrend = 'up';
      else if (ratioChange < -0.5) goldOilTrend = 'down';
    }
  }
}

// Calculate Risk Appetite Score (0-100)
// CNN F&G: 30% weight (direct)
// Crypto F&G: 20% weight (inverse - crypto leads risk-on)
// VIX: 30% weight (inverted - high VIX = fear = low score)
// DXY: 20% weight (inverse - high DXY = risk-off = low score)

// Normalize VIX to 0-100 scale (VIX typically 10-40, with extremes to 80+)
const vixNormalized = Math.max(0, Math.min(100, 100 - ((vixClose - 10) / 60 * 100)));

// Normalize DXY to 0-100 scale (DXY typically 95-105)
const dxyNormalized = Math.max(0, Math.min(100, 100 - ((dxyPrice - 95) / 15 * 100)));

const riskAppetiteScore = Math.round(
  (cnnScore * 0.30) +
  (cryptoScore * 0.20) +
  (vixNormalized * 0.30) +
  (dxyNormalized * 0.20)
);

// Classification
let classification;
if (riskAppetiteScore <= 20) classification = 'RISK OFF EXTREMO';
else if (riskAppetiteScore <= 40) classification = 'RISK OFF';
else if (riskAppetiteScore <= 59) classification = 'NEUTRAL';
else if (riskAppetiteScore <= 79) classification = 'RISK ON';
else classification = 'RISK ON EUFORIA';

// Generate interpretation
let lectura;
if (riskAppetiteScore <= 20) {
  lectura = 'Miedo extremo en los mercados. Posible sobreventa. Buscar oportunidades de compra en activos de riesgo.';
} else if (riskAppetiteScore <= 40) {
  lectura = 'Sesgo defensivo presente. Reducir exposición a riesgo, priorizar activos de bajo volatilidad.';
} else if (riskAppetiteScore <= 59) {
  lectura = 'Mercados en modo espera. Sin dirección clara. Mantener exposición neutral con gestión activa del tamaño.';
} else if (riskAppetiteScore <= 79) {
  lectura = 'Apetito por riesgo activo. Favorecer activos de mayor beta y trend following.';
} else {
  lectura = 'Euforia en los mercados. Extrema cautela con nuevos entries. Posible reversiónmedia inminente.';
}

// Build summary
const summary = `SENTIMENT SNAPSHOT — ${fecha} ${hora}
Risk Appetite: ${riskAppetiteScore}/100 — ${classification}
• CNN Fear & Greed: ${cnnScore} (${cnnRating}) ${cnnChangeYday >= 0 ? '+' : ''}${cnnChangeYday} vs ayer
• Crypto Fear & Greed: ${cryptoScore} (${cryptoRating}) ${cryptoChangeYday >= 0 ? '+' : ''}${cryptoChangeYday} vs ayer
• VIX: ${vixClose} (level: ${vixLevel}, ${vixChange5d >= 0 ? '+' : ''}${vixChange5d} 5d)
• DXY: ${dxyPrice} (${dxyChangeWeek >= 0 ? '+' : ''}${dxyChangeWeek}% semanal, trend: ${dxyTrend})
• Gold/Oil ratio: ${goldOilRatio} (trend: ${goldOilTrend})
LECTURA: ${lectura}`;

// Build data objects for storage
const sentimentData = {
  timestamp: now.toISOString(),
  fecha,
  hora,
  riskAppetiteScore,
  classification,
  cnnFearGreed: {
    score: cnnScore,
    rating: cnnRating,
    changeVsYesterday: cnnChangeYday,
    changeVsWeek: cnnChangeWeek
  },
  cryptoFearGreed: {
    score: cryptoScore,
    rating: cryptoRating,
    changeVsYesterday: cryptoChangeYday
  },
  vix: {
    value: vixClose,
    change5d: vixChange5d,
    level: vixLevel
  },
  dxy: {
    value: dxyPrice,
    changeWeekly: dxyChangeWeek,
    trend: dxyTrend
  },
  goldOilRatio: {
    value: goldOilRatio,
    goldPrice,
    oilPrice,
    trend: goldOilTrend
  },
  lectura
};

return [
  { json: { action: 'latest_json', data: sentimentData } },
  { json: { action: 'latest_txt', data: summary } }
];

// Read existing history or initialize empty array
let history = [];
try {
  const existing = require('/data/cache/sentiment_history.json');
  if (Array.isArray(existing)) {
    history = existing;
  }
} catch (e) {
  // File doesn't exist yet, start fresh
}

// Get current sentiment data from previous node
const currentData = $input.first().json.data;

// Add new entry
history.push({
  timestamp: currentData.timestamp,
  riskAppetiteScore: currentData.riskAppetiteScore,
  classification: currentData.classification
});

// Keep only last 24 hours (assuming hourly runs = 24 entries max, but be safe with 30)
const cutoff = Date.now() - (24 * 60 * 60 * 1000);
history = history.filter(entry => new Date(entry.timestamp).getTime() > cutoff);

// Also ensure we don't exceed 30 entries
if (history.length > 30) {
  history = history.slice(-30);
}

return [{ json: { history } }];
